#include <stdio.h>
#include <unistd.h>
#include <getopt.h>
#include <stdlib.h>
#include <assert.h>
#include <omp.h>

#include "common.h"

#ifdef TIMING
#include "timing.h"
#endif

#ifdef RD_WG_SIZE_0_0
        #define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
        #define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
        #define BLOCK_SIZE RD_WG_SIZE
#else
        #define BLOCK_SIZE 16
#endif

static int do_verify = 0;
int omp_num_threads = 40;

static struct option long_options[] = {

  {"input", 1, NULL, 'i'},
  {"size", 1, NULL, 's'},
  {"verify", 0, NULL, 'v'},
  {"threads", 1, NULL, 'n'},
  {0,0,0,0}
};

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif

void lud_diagonal(float *m, int matrix_dim, int offset)
{
  int i, j;
  float shadow[BLOCK_SIZE][BLOCK_SIZE];

  int array_offset = offset*matrix_dim+offset;
  for(i=0; i < BLOCK_SIZE; i++){
    for(int tx=0; tx < BLOCK_SIZE; tx++){
      shadow[i][tx] = m[array_offset+tx];
    }
    array_offset += matrix_dim;
  }

  for(i=0; i < BLOCK_SIZE-1; i++) {
    for(int tx=i+1; tx < BLOCK_SIZE; tx++){
      for(j=0; j < i; j++)
        shadow[tx][i] -= shadow[tx][j]*shadow[j][i];
      shadow[tx][i] /= shadow[i][i];
    }

    for(int tx=0; tx < BLOCK_SIZE; tx++){
      for(j=0; j < i+1; j++)
        shadow[i+1][tx] -= shadow[i+1][j]*shadow[j][tx];
    }
  }

  array_offset = (offset+1)*matrix_dim+offset;
  for(i=1; i < BLOCK_SIZE; i++){
    for(int tx=0; tx < BLOCK_SIZE; tx++){
      m[array_offset+tx] = shadow[i][tx];
    }
    array_offset += matrix_dim;
  }
}

void lud_perimeter(float *m, int matrix_dim, int offset, int block_idx)
{
  float dia[BLOCK_SIZE][BLOCK_SIZE];
  float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  float peri_col[BLOCK_SIZE][BLOCK_SIZE];

  int i, j, array_offset;
  int idx;

  // Load diagonal block
  array_offset = offset*matrix_dim+offset;
  for (i=0; i < BLOCK_SIZE; i++){
    for (idx=0; idx < BLOCK_SIZE; idx++){
      dia[i][idx] = m[array_offset+idx];
    }
    array_offset += matrix_dim;
  }

  // Load perimeter row
  array_offset = offset*matrix_dim+offset;
  for (i=0; i < BLOCK_SIZE; i++) {
    for (idx=0; idx < BLOCK_SIZE; idx++){
      peri_row[i][idx] = m[array_offset+(block_idx+1)*BLOCK_SIZE+idx];
    }
    array_offset += matrix_dim;
  }

  // Load perimeter column
  array_offset = (offset+(block_idx+1)*BLOCK_SIZE)*matrix_dim+offset;
  for (i=0; i < BLOCK_SIZE; i++) {
    for (idx=0; idx < BLOCK_SIZE; idx++){
      peri_col[i][idx] = m[array_offset+idx];
    }
    array_offset += matrix_dim;
  }

  // Update perimeter row
  for(i=1; i < BLOCK_SIZE; i++){
    for (idx=0; idx < BLOCK_SIZE; idx++){
      for (j=0; j < i; j++)
        peri_row[i][idx] -= dia[i][j]*peri_row[j][idx];
    }
  }

  // Update perimeter column
  for(i=0; i < BLOCK_SIZE; i++){
    for(idx=0; idx < BLOCK_SIZE; idx++){
      for(j=0; j < i; j++)
        peri_col[idx][i] -= peri_col[idx][j]*dia[j][i];
      peri_col[idx][i] /= dia[i][i];
    }
  }

  // Write back perimeter row
  array_offset = (offset+1)*matrix_dim+offset;
  for(i=1; i < BLOCK_SIZE; i++){
    for(idx=0; idx < BLOCK_SIZE; idx++){
      m[array_offset+(block_idx+1)*BLOCK_SIZE+idx] = peri_row[i][idx];
    }
    array_offset += matrix_dim;
  }

  // Write back perimeter column
  array_offset = (offset+(block_idx+1)*BLOCK_SIZE)*matrix_dim+offset;
  for(i=0; i < BLOCK_SIZE; i++){
    for(idx=0; idx < BLOCK_SIZE; idx++){
      m[array_offset+idx] = peri_col[i][idx];
    }
    array_offset += matrix_dim;
  }
}

void lud_internal(float *m, int matrix_dim, int offset, int block_row, int block_col)
{
  int i;
  float sum;

  int global_row_id = offset + (block_row+1)*BLOCK_SIZE;
  int global_col_id = offset + (block_col+1)*BLOCK_SIZE;

  float peri_row[BLOCK_SIZE];
  float peri_col[BLOCK_SIZE];

  // Load perimeter data
  for(int ty=0; ty < BLOCK_SIZE; ty++){
    peri_row[ty] = m[(offset+ty)*matrix_dim+global_col_id];
    peri_col[ty] = m[(global_row_id+ty)*matrix_dim+offset];
  }

  // Update internal block
  for(int ty=0; ty < BLOCK_SIZE; ty++){
    for(int tx=0; tx < BLOCK_SIZE; tx++){
      sum = 0;
      for (i=0; i < BLOCK_SIZE; i++)
        sum += peri_col[ty] * peri_row[i];
      m[(global_row_id+ty)*matrix_dim+global_col_id+tx] -= sum;
    }
  }
}

void lud_omp(float *m, int matrix_dim)
{
  int i;

  for (i=0; i < matrix_dim-BLOCK_SIZE; i += BLOCK_SIZE) {
      lud_diagonal(m, matrix_dim, i);

      #pragma omp parallel for
      for(int block_idx=0; block_idx < (matrix_dim-i)/BLOCK_SIZE-1; block_idx++){
        lud_perimeter(m, matrix_dim, i, block_idx);
      }

      #pragma omp parallel for collapse(2)
      for(int block_row=0; block_row < (matrix_dim-i)/BLOCK_SIZE-1; block_row++){
        for(int block_col=0; block_col < (matrix_dim-i)/BLOCK_SIZE-1; block_col++){
          lud_internal(m, matrix_dim, i, block_row, block_col);
        }
      }
  }
  lud_diagonal(m, matrix_dim, i);
}

int
main ( int argc, char *argv[] )
{
  printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);

  int matrix_dim = 32; 
  int opt, option_index=0;
  func_ret_t ret;
  const char *input_file = NULL;
  float *m, *mm;
  stopwatch sw;

  while ((opt = getopt_long(argc, argv, "::vs:n:i:", 
                            long_options, &option_index)) != -1 ) {
    switch(opt){
    case 'i':
      input_file = optarg;
      break;
    case 'v':
      do_verify = 1;
      break;
    case 'n':
      omp_num_threads = atoi(optarg);
      break;
    case 's':
      matrix_dim = atoi(optarg);
      printf("Generate input matrix internally, size =%d\n", matrix_dim);
      break;
    case '?':
      fprintf(stderr, "invalid option\n");
      break;
    case ':':
      fprintf(stderr, "missing argument\n");
      break;
    default:
      fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n",
	      argv[0]);
      exit(EXIT_FAILURE);
    }
  }

  if ( (optind < argc) || (optind == 1)) {
    fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n", argv[0]);
    exit(EXIT_FAILURE);
  }

  if (input_file) {
    printf("Reading matrix from file %s\n", input_file);
    ret = create_matrix_from_file(&m, input_file, &matrix_dim);
    if (ret != RET_SUCCESS) {
      m = NULL;
      fprintf(stderr, "error create matrix from file %s\n", input_file);
      exit(EXIT_FAILURE);
    }
  } 
  else if (matrix_dim) {
    printf("Creating matrix internally size=%d\n", matrix_dim);
    ret = create_matrix(&m, matrix_dim);
    if (ret != RET_SUCCESS) {
      m = NULL;
      fprintf(stderr, "error create matrix internally size=%d\n", matrix_dim);
      exit(EXIT_FAILURE);
    }
  }

  else {
    printf("No input file specified!\n");
    exit(EXIT_FAILURE);
  }

  if (do_verify){
    printf("Before LUD\n");

    matrix_duplicate(m, &mm, matrix_dim);
  }

  omp_set_num_threads(omp_num_threads);

  stopwatch_start(&sw);

#ifdef  TIMING
  gettimeofday(&tv_kernel_start, NULL);
#endif

  lud_omp(m, matrix_dim);

#ifdef  TIMING
  gettimeofday(&tv_kernel_end, NULL);
  tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
  kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

  stopwatch_stop(&sw);
  printf("Time consumed(ms): %lf\n", 1000*get_interval_by_sec(&sw));

  if (do_verify){
    printf("After LUD\n");

    printf(">>>Verify<<<<\n");
    lud_verify(mm, m, matrix_dim); 
    free(mm);
  }

  free(m);

#ifdef  TIMING
  printf("Exec: %f\n", kernel_time);
#endif

  return EXIT_SUCCESS;
}
